async function metaFetchJson(url: string) {
  const res = await fetch(url);
  const text = await res.text();
  let jsonBody: any = null;
  try {
    jsonBody = text ? JSON.parse(text) : null;
  } catch {
    jsonBody = null;
  }

  if (!res.ok) {
    const msg = jsonBody?.error?.message || `HTTP ${res.status}`;
    throw new Error(msg);
  }

  return jsonBody;
