}: {
  supabase: SupabaseAdmin;
  tenantId: string;
  publicationId: string;
  windowDays: 1 | 3 | 7;
}) {
  const fn = "meta-metrics-collect";

  // 1) Load publication
  const { data: pub, error: pubErr } = await supabase
    .from("content_publications")
    .select("id,tenant_id,case_id,channel,publish_status,meta_post_id,scheduled_at,created_at")
    .eq("id", publicationId)
    .maybeSingle();

  if (pubErr || !pub) {
    console.error(`[${fn}] publication not found`, { publicationId, error: pubErr?.message });
    return { ok: false as const, error: "publication_not_found" };
  }

  const row = pub as any as PublicationRow;
  if (row.tenant_id !== tenantId) {
    console.error(`[${fn}] tenant mismatch`, { tenantId, publicationTenantId: row.tenant_id, publicationId });
    return { ok: false as const, error: "tenant_mismatch" };
  }

  if (row.publish_status !== "PUBLISHED" || !row.meta_post_id) {
    return { ok: false as const, error: "publication_not_published" };
  }

  // 2) Meta account
  const acc = await getActiveMetaAccount({ supabase, tenantId });
  if (!acc.ok) {
    return { ok: false as const, error: `meta_account:${acc.error}` };
  }

  const igAccountId = String(acc.meta.ig_business_account_id);
  const accessToken = acc.accessToken;
  const mediaId = String(row.meta_post_id);

  // 3) Compute window (best-effort: scheduled_at else created_at)
  const base = row.scheduled_at ?? row.created_at;
  const sinceIso = base;
  const untilIso = addDaysIso(base, windowDays);

  // 4) Fetch metrics
  // 4.1) Media impressions
  let impressions: number | null = null;
  try {
    const url = `https://graph.facebook.com/${GRAPH_VERSION}/${encodeURIComponent(mediaId)}/insights?metric=impressions&access_token=${encodeURIComponent(accessToken)}`;
    const res = await metaFetchJson(url);
    impressions = pickInsightValue(res, "impressions");
  } catch (e: any) {
    console.warn(`[${fn}] media insights failed (impressions)`, { publicationId, mediaId, error: e?.message ?? String(e) });
  }

  // 4.2) Account-level deltas in the window
  // Mapping (best-effort):
  // - profile_visits -> profile_views
  // - follows -> follower_count (new followers)
  // - messages -> profile_replies (story replies)
  let profileVisits: number | null = null;
  let follows: number | null = null;
  let messages: number | null = null;

  try {
    const params = new URLSearchParams({
      metric: "profile_views,follower_count,profile_replies",
      period: "day",
      since: Math.floor(new Date(sinceIso).getTime() / 1000).toString(),
      until: Math.floor(new Date(untilIso).getTime() / 1000).toString(),
      access_token: accessToken,
    });

    const url = `https://graph.facebook.com/${GRAPH_VERSION}/${encodeURIComponent(igAccountId)}/insights?${params.toString()}`;
    const res = await metaFetchJson(url);

    profileVisits = pickInsightValue(res, "profile_views");
    follows = pickInsightValue(res, "follower_count");
    messages = pickInsightValue(res, "profile_replies");
  } catch (e: any) {
    console.warn(`[${fn}] account insights failed (window)`, { publicationId, igAccountId, error: e?.message ?? String(e) });
  }

  const metrics = {
    impressions,
    profile_visits: profileVisits,
    follows,
    messages,
    window: { days: windowDays, since: sinceIso, until: untilIso },
  };

  // 5) Upsert snapshot
  const { data: snap, error: upErr } = await supabase
    .from("content_metrics_snapshots")
    .upsert(
      {
        tenant_id: tenantId,
        publication_id: publicationId,
        window_days: windowDays,
        impressions,
        profile_visits: profileVisits,
        follows,
        messages,
        metrics_json: metrics,
        collected_at: new Date().toISOString(),
      },
      { onConflict: "tenant_id,publication_id,window_days" }
    )
    .select("id")
    .maybeSingle();

  if (upErr) {
    console.error(`[${fn}] upsert snapshot failed`, { tenantId, publicationId, windowDays, error: upErr?.message });
    return { ok: false as const, error: "snapshot_upsert_failed" };
  }

  return {
    ok: true as const,
    snapshot_id: String((snap as any)?.id ?? ""),
    publication: { id: publicationId, case_id: row.case_id, channel: row.channel },
    metrics,
  };
}

import { decryptText } from "./encryption.ts";

const GRAPH_VERSION = "v19.0";

type SupabaseAdmin = any;

type PublishStatus = "DRAFT" | "SCHEDULED" | "PUBLISHED" | "FAILED" | "ASSISTED_REQUIRED";

type PublicationRow = {
  id: string;
  tenant_id: string;
  case_id: string | null;
  content_item_id: string;
  channel: "ig_story" | "ig_feed" | "ig_reels" | "fb_feed" | string;
  caption_text: string | null;
  creative_type: "IMAGE" | "VIDEO" | "CAROUSEL" | "MIXED" | null;
  media_storage_paths: string[];
  scheduled_at: string | null;
  publish_status: PublishStatus;
};

type MetaAccountRow = {
  id: string;
  tenant_id: string;
  ig_business_account_id: string;
  fb_page_id: string;
  fb_page_name: string;
  ig_username: string | null;
  access_token_encrypted: string;
  token_expires_at: string | null;
  scopes: string[] | null;
  is_active: boolean;
};

function isAllowedChannel(channel: string) {
  return channel === "ig_feed" || channel === "ig_story";
}

function isProbablyNotSupported(msg: string) {
  const m = (msg ?? "").toLowerCase();
  return (
    m.includes("not supported") ||
    m.includes("unsupported") ||
    m.includes("instagram_content_publish") ||
    m.includes("permissions") ||
    m.includes("permission") ||
    m.includes("requires")
  );
}

async function metaFetchJson(url: string, opts?: RequestInit) {
  const res = await fetch(url, opts);
  const text = await res.text();
  let jsonBody: any = null;
  try {
    jsonBody = text ? JSON.parse(text) : null;
  } catch {
    jsonBody = null;
  }

  if (!res.ok) {
    const msg = jsonBody?.error?.message || `HTTP ${res.status}`;
    throw new Error(msg);
  }

  return jsonBody;
}

async function createContainer({
  igAccountId,
  accessToken,
  channel,
  creativeType,
  mediaUrl,
  caption,
}: {
  igAccountId: string;
  accessToken: string;
  channel: "ig_feed" | "ig_story";
  creativeType: "IMAGE" | "VIDEO";
  mediaUrl: string;
  caption: string | null;
}) {
  const params = new URLSearchParams({
    access_token: accessToken,
  });

  if (channel === "ig_story") {
    params.set("media_type", "STORIES");
    if (creativeType === "VIDEO") params.set("video_url", mediaUrl);
    else params.set("image_url", mediaUrl);
    // Stories: caption is not consistently supported; avoid breaking.
  } else {
    if (creativeType === "VIDEO") {
      params.set("media_type", "VIDEO");
      params.set("video_url", mediaUrl);
    } else {
      params.set("image_url", mediaUrl);
    }
    if (caption?.trim()) params.set("caption", caption.trim());
  }

  const url = `https://graph.facebook.com/${GRAPH_VERSION}/${encodeURIComponent(igAccountId)}/media`;
  return await metaFetchJson(url, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: params.toString(),
  });
}

async function publishContainer({
  igAccountId,
  accessToken,
  creationId,
}: {
  igAccountId: string;
  accessToken: string;
  creationId: string;
}) {
  const params = new URLSearchParams({
    access_token: accessToken,
    creation_id: creationId,
  });
  const url = `https://graph.facebook.com/${GRAPH_VERSION}/${encodeURIComponent(igAccountId)}/media_publish`;
  return await metaFetchJson(url, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: params.toString(),
  });
}

async function fetchPermalink({
  mediaId,
  accessToken,
}: {
  mediaId: string;
  accessToken: string;
}) {
  const params = new URLSearchParams({
    fields: "permalink",
    access_token: accessToken,
  });
  const url = `https://graph.facebook.com/${GRAPH_VERSION}/${encodeURIComponent(mediaId)}?${params.toString()}`;
  const j = await metaFetchJson(url);
  return (j?.permalink as string | undefined) ?? null;
}

function publicStorageUrl(bucket: string, path: string) {
  const projectRef = Deno.env.get("SUPABASE_PROJECT_REF") ?? "pryoirzeghatrgecwrci";
  // Bucket is public (phase1 migration). This yields a stable public URL.
  return `https://${projectRef}.supabase.co/storage/v1/object/public/${bucket}/${path}`;
}

async function createHumanTask({
  supabase,
  tenantId,
  caseId,
  publicationId,
  title,
  description,
  errorMessage,
}: {
  supabase: SupabaseAdmin;
  tenantId: string;
  caseId: string | null;
  publicationId: string;
  title: string;
  description: string;
  errorMessage: string | null;
}) {
  // Task
  await supabase.from("tasks").insert({
    tenant_id: tenantId,
    case_id: caseId,
    title,
    description: `${description}${errorMessage ? `\n\nErro: ${errorMessage}` : ""}`,
    assigned_to_role: "admin",
    status: "open",
    due_at: new Date(Date.now() + 2 * 60 * 60 * 1000).toISOString(),
    created_by: "system",
    meta_json: { kind: "meta_publish", publication_id: publicationId },
  });

  // Timeline
  if (caseId) {
    await supabase.from("timeline_events").insert({
      tenant_id: tenantId,
      case_id: caseId,
      event_type: "content_publish_attention_required",
      actor_type: "system",
      actor_id: null,
      message: title,
      meta_json: { publication_id: publicationId, error: errorMessage },
      occurred_at: new Date().toISOString(),
    });
  }

  // Audit ledger (best-effort)
  try {
    await supabase.rpc("append_audit_ledger", {
      p_tenant_id: tenantId,
      p_payload: { kind: "meta_publish_attention_required", publication_id: publicationId, case_id: caseId },
    });
  } catch {
    // ignore
  }
}

export async function publishContentPublication({
  supabase,
  tenantId,
  publicationId,
  requestedByUserId,
}: {
  supabase: SupabaseAdmin;
  tenantId: string;
  publicationId: string;
  requestedByUserId?: string | null;
}) {
  const fn = "meta-publish";

  // 1) Load publication (hard tenant boundary)
  const { data: pub, error: pubErr } = await supabase
    .from("content_publications")
    .select(
      "id,tenant_id,case_id,content_item_id,channel,caption_text,creative_type,media_storage_paths,scheduled_at,publish_status"
    )
    .eq("id", publicationId)
    .maybeSingle();

  if (pubErr || !pub) {
    console.error(`[${fn}] publication not found`, { publicationId, error: pubErr?.message });
    return { ok: false as const, status: "FAILED" as PublishStatus, error: "publication_not_found" };
  }

  const row = pub as any as PublicationRow;

  if (row.tenant_id !== tenantId) {
    console.error(`[${fn}] tenant mismatch`, { tenantId, publicationTenantId: row.tenant_id, publicationId });
    return { ok: false as const, status: "FAILED" as PublishStatus, error: "tenant_mismatch" };
  }

  if (row.publish_status === "PUBLISHED") {
    return { ok: true as const, status: row.publish_status, id: row.id };
  }

  // 2) Only IG Feed + Stories for this phase
  if (!isAllowedChannel(row.channel)) {
    const message = `Canal não suportado para autopublish nesta fase: ${row.channel}`;
    await supabase
      .from("content_publications")
      .update({ publish_status: "ASSISTED_REQUIRED", last_error: message })
      .eq("tenant_id", tenantId)
      .eq("id", publicationId);

    await createHumanTask({
      supabase,
      tenantId,
      caseId: row.case_id,
      publicationId,
      title: `Publicação requer ação humana (${row.channel})`,
      description: `Autopublish não suportado para este canal nesta fase.`,
      errorMessage: message,
    });

    return { ok: false as const, status: "ASSISTED_REQUIRED" as const, error: message };
  }

  // 3) Resolve active Meta account
  const { data: acc, error: accErr } = await supabase
    .from("meta_accounts")
    .select(
      "id,tenant_id,ig_business_account_id,fb_page_id,fb_page_name,ig_username,access_token_encrypted,token_expires_at,scopes,is_active"
    )
    .eq("tenant_id", tenantId)
    .eq("is_active", true)
    .order("created_at", { ascending: false })
    .limit(1)
    .maybeSingle();

  if (accErr || !acc) {
    const message = "Nenhuma meta_accounts ativa encontrada para o tenant.";
    await supabase
      .from("content_publications")
      .update({ publish_status: "ASSISTED_REQUIRED", last_error: message })
      .eq("tenant_id", tenantId)
      .eq("id", publicationId);

    await createHumanTask({
      supabase,
      tenantId,
      caseId: row.case_id,
      publicationId,
      title: "Conectar conta Meta para publicar",
      description: "Não foi encontrada conta Meta ativa. Conecte em Integrações → Meta.",
      errorMessage: message,
    });

    return { ok: false as const, status: "ASSISTED_REQUIRED" as const, error: message };
  }

  const meta = acc as any as MetaAccountRow;

  if (meta.token_expires_at && new Date(meta.token_expires_at).getTime() < Date.now()) {
    const message = "Token Meta expirado. Refaça a conexão da conta.";
    await supabase
      .from("content_publications")
      .update({ publish_status: "ASSISTED_REQUIRED", last_error: message })
      .eq("tenant_id", tenantId)
      .eq("id", publicationId);

    await createHumanTask({
      supabase,
      tenantId,
      caseId: row.case_id,
      publicationId,
      title: "Token Meta expirado",
      description: "A conta Meta está conectada, mas o token expirou. Refaça a conexão em Integrações → Meta.",
      errorMessage: message,
    });

    return { ok: false as const, status: "ASSISTED_REQUIRED" as const, error: message };
  }

  // 4) Validate media
  const mediaPaths = Array.isArray(row.media_storage_paths) ? row.media_storage_paths.filter(Boolean) : [];
  const caption = row.caption_text ?? null;

  // Only handle single media (MVP)
  if (mediaPaths.length !== 1) {
    const message =
      mediaPaths.length === 0
        ? "Publicação sem mídia. Faça upload (imagem/vídeo) antes de publicar."
        : "Autopublish suporta apenas 1 mídia nesta fase. Use publicação assistida.";

    const nextStatus: PublishStatus = "ASSISTED_REQUIRED";

    await supabase
      .from("content_publications")
      .update({ publish_status: nextStatus, last_error: message })
      .eq("tenant_id", tenantId)
      .eq("id", publicationId);

    await createHumanTask({
      supabase,
      tenantId,
      caseId: row.case_id,
      publicationId,
      title: "Publicação requer ação humana (mídia)",
      description: "A publicação não está em um formato suportado para autopublish.",
      errorMessage: message,
    });

    return { ok: false as const, status: nextStatus, error: message };
  }

  const mediaUrl = publicStorageUrl("content-media", mediaPaths[0]);

  // Creative type inference
  const ct = (row.creative_type ?? "IMAGE") as any;
  const creativeType: "IMAGE" | "VIDEO" = ct === "VIDEO" ? "VIDEO" : "IMAGE";

  // 5) Publish via Graph API
  let accessToken = "";
  try {
    accessToken = await decryptText(meta.access_token_encrypted);
  } catch (e: any) {
    const message = `Falha ao descriptografar token Meta: ${e?.message ?? "erro"}`;
    await supabase
      .from("content_publications")
      .update({ publish_status: "ASSISTED_REQUIRED", last_error: message })
      .eq("tenant_id", tenantId)
      .eq("id", publicationId);

    await createHumanTask({
      supabase,
      tenantId,
      caseId: row.case_id,
      publicationId,
      title: "Token Meta inválido",
      description: "Falha ao descriptografar token. Refaça a conexão em Integrações → Meta.",
      errorMessage: message,
    });

    return { ok: false as const, status: "ASSISTED_REQUIRED" as const, error: message };
  }

  const igAccountId = String(meta.ig_business_account_id);

  try {
    console.log(`[${fn}] publishing`, {
      tenantId,
      publicationId,
      channel: row.channel,
      igAccountId,
      by: requestedByUserId ?? "system",
    });

    const container = await createContainer({
      igAccountId,
      accessToken,
      channel: row.channel as any,
      creativeType,
      mediaUrl,
      caption,
    });

    const creationId = String(container?.id ?? "");
    if (!creationId) throw new Error("Missing creation id");

    const published = await publishContainer({ igAccountId, accessToken, creationId });
    const mediaId = String(published?.id ?? "");
    if (!mediaId) throw new Error("Missing media id");

    const permalink = await fetchPermalink({ mediaId, accessToken }).catch(() => null);

    await supabase
      .from("content_publications")
      .update({
        publish_status: "PUBLISHED",
        meta_post_id: mediaId,
        meta_permalink: permalink,
        last_error: null,
      })
      .eq("tenant_id", tenantId)
      .eq("id", publicationId);

    // NEW: enqueue metrics snapshots (D+1, D+3, D+7)
    try {
      const windows = [1, 3, 7] as const;
      for (const d of windows) {
        const idempotencyKey = `META_COLLECT_METRICS:${publicationId}:D${d}`;
        const runAfter = new Date(Date.now() + d * 24 * 60 * 60 * 1000).toISOString();

        const { error } = await supabase.from("job_queue").insert({
          tenant_id: tenantId,
          type: "META_COLLECT_METRICS",
          idempotency_key: idempotencyKey,
          payload_json: { publication_id: publicationId, window_days: d },
          status: "pending",
          run_after: runAfter,
        });

        if (error) {
          const msg = String((error as any)?.message ?? "").toLowerCase();
          if (!msg.includes("duplicate")) {
            console.warn(`[${fn}] Failed to enqueue META_COLLECT_METRICS (ignored)`, { tenantId, publicationId, d, error });
          }
        }
      }
    } catch (e: any) {
      console.warn(`[${fn}] enqueue metrics jobs failed (ignored)`, { tenantId, publicationId, error: e?.message ?? String(e) });
    }

    if (row.case_id) {
      await supabase.from("timeline_events").insert({
        tenant_id: tenantId,
        case_id: row.case_id,
        event_type: "content_published",
        actor_type: requestedByUserId ? "admin" : "system",
        actor_id: requestedByUserId ?? null,
        message: `Publicado (${row.channel}).`,
        meta_json: { publication_id: publicationId, meta_post_id: mediaId },
        occurred_at: new Date().toISOString(),
      });
    }

    try {
      await supabase.rpc("append_audit_ledger", {
        p_tenant_id: tenantId,
        p_payload: { kind: "meta_published", publication_id: publicationId, meta_post_id: mediaId },
      });
    } catch {
      // ignore
    }

    return { ok: true as const, status: "PUBLISHED" as const, meta_post_id: mediaId, meta_permalink: permalink };
  } catch (e: any) {
    const message = String(e?.message ?? "publish_failed");
    const assisted = isProbablyNotSupported(message);
    const nextStatus: PublishStatus = assisted ? "ASSISTED_REQUIRED" : "FAILED";

    await supabase
      .from("content_publications")
      .update({ publish_status: nextStatus, last_error: message })
      .eq("tenant_id", tenantId)
      .eq("id", publicationId);

    await createHumanTask({
      supabase,
      tenantId,
      caseId: row.case_id,
      publicationId,
      title: assisted ? "Publicação requer ação humana" : "Falha ao publicar automaticamente",
      description: assisted
        ? "A API da Meta indicou que este formato/conta não suporta autopublish. Faça publicação assistida." 
        : "A publicação automática falhou. Verifique o erro e tente novamente ou publique assistido.",
      errorMessage: message,
    });

    console.error(`[${fn}] publish failed`, { tenantId, publicationId, message, nextStatus });

    return { ok: false as const, status: nextStatus, error: message };
  }
}

export function normalizePhoneE164Like(input: string | null | undefined) {
  if (!input) return null;

  const raw = String(input).trim();
  if (!raw) return null;

  // Preserve WhatsApp Group and Broadcast IDs
  const lower = raw.toLowerCase();
  if (lower.includes("@g.us") || lower.includes("@broadcast") || lower.includes("-") || (lower.startsWith("1203") && lower.length > 15)) {
    return raw;
  }

  // Extract digits (ignoring @lid or other artifacts)
  let digits = raw.replace(/\D/g, "");
  if (!digits) return null;

  // Some providers prefix with 00 (international dialing). Strip it.
  digits = digits.replace(/^00+/, "");

  // Trunk code removal for BR specifically (starts with 0 + 11 or 12 digits, meaning 011999999999)
  if (digits.startsWith("0") && (digits.length === 11 || digits.length === 12)) {
    digits = digits.slice(1);
  }

  // BR validation (starts with 55)
  if (digits.startsWith("55")) {
    if (digits.length !== 12 && digits.length !== 13) return null;
    return `+${digits}`;
  }

  // Other country codes support
  // If the number doesn't start with 55, it might already include a valid country code. 
  // Global numbers generally have between 10 and 15 digits.
  if (digits.length >= 10 && digits.length <= 15) {
    // If it looks like a BR number without 55 (10-11 digits), prepend 55.
    if (digits.length === 10 || digits.length === 11) {
      return `+55${digits}`;
    }
    // Otherwise, assume it's an international number that already includes its country code.
    return `+${digits}`;
  }

  return null;
}

export function nowIso() {
  return new Date().toISOString();
}

type MetricPoint = {
  window_days: number;
  impressions: number | null;
  profile_visits: number | null;
  follows: number | null;
  messages: number | null;
};

function safeNum(n: any) {
  return typeof n === "number" && Number.isFinite(n) ? n : null;
}

function diff(a: number | null, b: number | null) {
  if (a == null || b == null) return null;
  return b - a;
}

function pct(a: number | null, b: number | null) {
  if (a == null || b == null || a <= 0) return null;
  return (b - a) / a;
}

function fmtPct(v: number) {
  const p = Math.round(v * 100);
  return `${p}%`;
}

export function buildPerformanceReport({
  points,
  channel,
}: {
  points: MetricPoint[];
  channel: string;
}) {
  const sorted = [...points]
    .map((p) => ({
      window_days: p.window_days,
      impressions: safeNum(p.impressions),
      profile_visits: safeNum(p.profile_visits),
      follows: safeNum(p.follows),
      messages: safeNum(p.messages),
    }))
    .sort((a, b) => a.window_days - b.window_days);

  const last = sorted[sorted.length - 1] ?? null;
  const d1 = sorted.find((p) => p.window_days === 1) ?? null;
  const d3 = sorted.find((p) => p.window_days === 3) ?? null;
  const d7 = sorted.find((p) => p.window_days === 7) ?? null;

  const growth = {
    imp_d1_d3: d1 ? diff(d1.impressions, d3?.impressions ?? null) : null,
    imp_d3_d7: d3 ? diff(d3.impressions, d7?.impressions ?? null) : null,
    imp_pct_d1_d3: d1 ? pct(d1.impressions, d3?.impressions ?? null) : null,
    imp_pct_d3_d7: d3 ? pct(d3.impressions, d7?.impressions ?? null) : null,
  };

  const patterns: string[] = [];
  const recommendations: string[] = [];

  if (last?.impressions != null) {
    if (last.impressions < 500) patterns.push("Alcance baixo para o período — provável falta de distribuição inicial ou criativo pouco atrativo.");
    else if (last.impressions < 3000) patterns.push("Alcance moderado — há tração, mas ainda com espaço para otimização.");
    else patterns.push("Alcance forte — conteúdo com boa distribuição e interesse inicial.");
  } else {
    patterns.push("Impressões não disponíveis via API para este post/conta (ver permissões e tipo de mídia). ");
  }

  if (growth.imp_pct_d1_d3 != null) {
    if (growth.imp_pct_d1_d3 < 0.15) patterns.push("Crescimento fraco após D+1 — o post não ganhou ‘segunda onda’. ");
    else patterns.push(`Crescimento saudável após D+1 (+${fmtPct(growth.imp_pct_d1_d3)} até D+3).`);
  }

  if (growth.imp_pct_d3_d7 != null) {
    if (growth.imp_pct_d3_d7 < 0.1) patterns.push("Conteúdo esgota rápido — pouca cauda longa.");
    else patterns.push(`Boa cauda longa (+${fmtPct(growth.imp_pct_d3_d7)} entre D+3 e D+7).`);
  }

  if (channel === "ig_story") {
    recommendations.push("Use stickers (enquete/pergunta) para aumentar replies; isso melhora retenção e sinais de conversa.");
    recommendations.push("Abra com um gancho nos 2 primeiros segundos (texto grande + promessa clara).");
  } else {
    recommendations.push("Otimize a primeira linha da legenda (gancho) e inclua CTA claro (salvar, comentar, enviar). ");
    recommendations.push("Teste variações de capa e 1º frame — o CTR do feed depende muito disso.");
  }

  recommendations.push("Republique nos Stories nas primeiras 24h com contexto (‘por que isso importa’).");
  recommendations.push("Padronize horários: replique em 2-3 janelas por semana e compare D+1 vs D+3.");

  const summaryParts: string[] = [];
  summaryParts.push(`Canal: ${channel}.`);
  if (last?.impressions != null) summaryParts.push(`Impressões até D+${last.window_days}: ${last.impressions}.`);
  if (last?.profile_visits != null) summaryParts.push(`Visitas ao perfil (janela): ${last.profile_visits}.`);
  if (last?.follows != null) summaryParts.push(`Novos follows (janela): ${last.follows}.`);
  if (last?.messages != null) summaryParts.push(`Mensagens/replies (janela): ${last.messages}.`);

  const reportText =
    `Resumo\n` +
    `- ${summaryParts.join(" ")}\n\n` +
    `Padrões observados\n` +
    patterns.map((p) => `- ${p}`).join("\n") +
    `\n\nRecomendações\n` +
    recommendations.map((r) => `- ${r}`).join("\n");

  return {
    summary: summaryParts.join(" "),
    patterns,
    recommendations,
    reportText,
    derived: { growth },
  };
}

export type PresencePunchType = "ENTRY" | "BREAK_START" | "BREAK_END" | "BREAK2_START" | "BREAK2_END" | "EXIT";
export type PresencePunchSource = "APP" | "WHATSAPP";

export function getLocalYmd(timeZone: string, d = new Date()) {
  const dtf = new Intl.DateTimeFormat("en-CA", {
    timeZone,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  });
  return dtf.format(d); // YYYY-MM-DD
}

export function inferNextPunchType(last: PresencePunchType | null, breakRequired: boolean): PresencePunchType | null {
  if (!last) return "ENTRY";
  if (last === "ENTRY") return breakRequired ? "BREAK_START" : "EXIT";
  if (last === "BREAK_START") return "BREAK_END";
  if (last === "BREAK_END") return "EXIT";
  return null;
}

import type { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";
import {
  type PresencePunchType,
  type PresencePunchSource,
  inferNextPunchType,
  getLocalYmd,
} from "./presence-logic.ts";

export type { PresencePunchType, PresencePunchSource };
export { getLocalYmd, inferNextPunchType };

type PresencePolicy = {
  id: string;
  location_id: string;
  radius_meters: number;
  lateness_tolerance_minutes: number;
  break_required: boolean;
  allow_outside_radius: boolean;
  presence_locations?: {
    id: string;
    name: string;
    latitude: number;
    longitude: number;
  } | null;
};

type PresenceEmployeeConfig = {
  scheduled_start_hhmm: string | null;
  planned_minutes: number | null;
} | null;

function getLocalHm(timeZone: string, d = new Date()) {
  const dtf = new Intl.DateTimeFormat("en-GB", {
    timeZone,
    hour: "2-digit",
    minute: "2-digit",
    hourCycle: "h23",
  });
  const s = dtf.format(d);
  const [hh, mm] = s.split(":");
  return { hh: Number(hh), mm: Number(mm) };
}

function minutesOfDay(hh: number, mm: number) {
  return hh * 60 + mm;
}

function parseHHMM(s: string, fallback = "08:00") {
  const raw = (s || fallback).trim();
  const m = raw.match(/^(\d{1,2}):(\d{2})$/);
  if (!m) return { hh: 8, mm: 0 };
  const hh = Math.max(0, Math.min(23, Number(m[1])));
  const mm = Math.max(0, Math.min(59, Number(m[2])));
  return { hh, mm };
}

function haversineMeters(a: { lat: number; lng: number }, b: { lat: number; lng: number }) {
  const R = 6371000;
  const toRad = (deg: number) => (deg * Math.PI) / 180;
  const dLat = toRad(b.lat - a.lat);
  const dLng = toRad(b.lng - a.lng);
  const lat1 = toRad(a.lat);
  const lat2 = toRad(b.lat);

  const s1 = Math.sin(dLat / 2);
  const s2 = Math.sin(dLng / 2);
  const h = s1 * s1 + Math.cos(lat1) * Math.cos(lat2) * s2 * s2;
  return 2 * R * Math.asin(Math.sqrt(h));
}

export async function getPresenceTenantConfig(
  supabase: SupabaseClient,
  tenantId: string
): Promise<
  | {
    enabled: boolean;
    journeyId: string | null;
    config: any;
    flags: { presence_enabled: boolean; presence_allow_whatsapp_clocking: boolean };
    presence: { time_zone: string; scheduled_start_hhmm: string; planned_minutes: number };
  }
  | { enabled: false; journeyId: null; config: any; flags: any; presence: any }
> {
  const { data, error } = await supabase
    .from("tenant_journeys")
    .select("journey_id, config_json, journeys!inner(key)")
    .eq("tenant_id", tenantId)
    .eq("enabled", true)
    .eq("journeys.key", "presence")
    .limit(1)
    .maybeSingle();

  if (error) throw error;

  const cfg = (data as any)?.config_json ?? {};
  const flags = (cfg?.flags ?? {}) as any;
  const presenceCfg = (cfg?.presence ?? {}) as any;

  const enabled = Boolean(flags?.presence_enabled === true);

  return {
    enabled,
    journeyId: (data as any)?.journey_id ?? null,
    config: cfg,
    flags: {
      presence_enabled: enabled,
      presence_allow_whatsapp_clocking: Boolean(flags?.presence_allow_whatsapp_clocking === true),
    },
    presence: {
      time_zone: String(presenceCfg?.time_zone ?? "America/Sao_Paulo"),
      scheduled_start_hhmm: String(presenceCfg?.scheduled_start_hhmm ?? "08:00"),
      planned_minutes: Number(presenceCfg?.planned_minutes ?? 480),
    },
  };
}

export async function getPresencePolicy(supabase: SupabaseClient, tenantId: string): Promise<PresencePolicy | null> {
  const { data, error } = await supabase
    .from("presence_policies")
    .select(
      "id,location_id,radius_meters,lateness_tolerance_minutes,break_required,allow_outside_radius,presence_locations(id,name,latitude,longitude)"
    )
    .eq("tenant_id", tenantId)
    .order("created_at", { ascending: true })
    .limit(1)
    .maybeSingle();

  if (error) throw error;
  return (data as any) ?? null;
}

export async function getPresenceEmployeeConfig(
  supabase: SupabaseClient,
  tenantId: string,
  employeeId: string
): Promise<PresenceEmployeeConfig> {
  try {
    const { data, error } = await supabase
      .from("presence_employee_configs")
      .select("scheduled_start_hhmm,planned_minutes")
      .eq("tenant_id", tenantId)
      .eq("employee_id", employeeId)
      .limit(1)
      .maybeSingle();

    if (error) return null;

    return {
      scheduled_start_hhmm: (data as any)?.scheduled_start_hhmm ?? null,
      planned_minutes: (data as any)?.planned_minutes ?? null,
    };
  } catch {
    return null;
  }
}



export async function ensurePresenceDayCase(args: {
  supabase: SupabaseClient;
  tenantId: string;
  employeeId: string;
  journeyId: string;
  timeZone: string;
}) {
  const { supabase, tenantId, employeeId, journeyId, timeZone } = args;
  const day = getLocalYmd(timeZone);

  const { data: existing, error: exErr } = await supabase
    .from("cases")
    .select("id,state,status,case_date")
    .eq("tenant_id", tenantId)
    .eq("case_type", "PRESENCE_DAY")
    .eq("entity_type", "employee")
    .eq("entity_id", employeeId)
    .eq("case_date", day)
    .is("deleted_at", null)
    .limit(1)
    .maybeSingle();

  if (exErr) throw exErr;
  if ((existing as any)?.id) return { caseId: (existing as any).id as string, day };

  // Best-effort label to avoid managers needing access to users_profile.
  let employeeLabel: string | null = null;
  try {
    const { data: prof } = await supabase
      .from("users_profile")
      .select("display_name,email")
      .eq("tenant_id", tenantId)
      .eq("user_id", employeeId)
      .is("deleted_at", null)
      .maybeSingle();
    employeeLabel =
      (prof as any)?.display_name ||
      ((prof as any)?.email ? String((prof as any).email).split("@")[0] : null);
  } catch {
    employeeLabel = null;
  }

  const { data: created, error: cErr } = await supabase
    .from("cases")
    .insert({
      tenant_id: tenantId,
      journey_id: journeyId,
      case_type: "PRESENCE_DAY",
      status: "open",
      state: "AGUARDANDO_ENTRADA",
      created_by_channel: "panel",
      title: employeeLabel ? `Ponto • ${day} • ${employeeLabel}` : `Ponto • ${day}`,
      entity_type: "employee",
      entity_id: employeeId,
      case_date: day,
      meta_json: {
        journey_key: "presence",
        presence: { day, employee_label: employeeLabel },
      },
    })
    .select("id")
    .single();

  if (cErr) {
    // Possible unique race — try fetch again.
    const { data: again, error: aErr } = await supabase
      .from("cases")
      .select("id")
      .eq("tenant_id", tenantId)
      .eq("case_type", "PRESENCE_DAY")
      .eq("entity_type", "employee")
      .eq("entity_id", employeeId)
      .eq("case_date", day)
      .is("deleted_at", null)
      .limit(1)
      .maybeSingle();
    if (aErr) throw cErr;
    if ((again as any)?.id) return { caseId: (again as any).id as string, day };
    throw cErr;
  }

  return { caseId: (created as any).id as string, day };
}

export async function clockPresencePunch(args: {
  supabase: SupabaseClient;
  tenantId: string;
  employeeId: string;
  source: PresencePunchSource;
  latitude: number | null;
  longitude: number | null;
  accuracyMeters: number | null;
  forcedType?: PresencePunchType | null;
  actorType: "admin" | "system";
  actorId: string | null;
}) {
  const { supabase, tenantId, employeeId, source, latitude, longitude, accuracyMeters, forcedType, actorType, actorId } =
    args;

  const tenantCfg = await getPresenceTenantConfig(supabase, tenantId);
  if (!tenantCfg.enabled || !tenantCfg.journeyId) {
    return { ok: false as const, error: "presence_not_enabled" };
  }

  const policy = await getPresencePolicy(supabase, tenantId);
  const breakRequired = policy?.break_required ?? true;

  const employeeCfg = await getPresenceEmployeeConfig(supabase, tenantId, employeeId);
  const scheduledStartHhmm = employeeCfg?.scheduled_start_hhmm || tenantCfg.presence.scheduled_start_hhmm;

  const { caseId, day } = await ensurePresenceDayCase({
    supabase,
    tenantId,
    employeeId,
    journeyId: tenantCfg.journeyId,
    timeZone: tenantCfg.presence.time_zone,
  });

  // last punch
  const { data: lastPunch, error: lpErr } = await supabase
    .from("time_punches")
    .select("id,type,timestamp,within_radius,distance_from_location,status")
    .eq("tenant_id", tenantId)
    .eq("case_id", caseId)
    .order("timestamp", { ascending: false })
    .limit(1)
    .maybeSingle();

  if (lpErr) throw lpErr;

  const lastType = (lastPunch as any)?.type ? (String((lastPunch as any).type) as PresencePunchType) : null;
  const inferred = inferNextPunchType(lastType, breakRequired);

  if (forcedType && inferred && forcedType !== inferred) {
    return {
      ok: false as const,
      error: "invalid_sequence",
      expected: inferred,
      got: forcedType,
    };
  }

  const nextType = forcedType ?? inferred;

  if (!nextType) {
    return { ok: false as const, error: "no_next_action" };
  }

  // Geofence
  let withinRadius = true;
  let distanceFromLocation: number | null = null;
  let punchStatus: "VALID" | "VALID_WITH_EXCEPTION" | "PENDING_REVIEW" = "VALID";
  let locationName: string | null = null;

  if (policy?.presence_locations && latitude != null && longitude != null) {
    locationName = policy.presence_locations.name;
    distanceFromLocation = haversineMeters(
      { lat: latitude, lng: longitude },
      { lat: policy.presence_locations.latitude, lng: policy.presence_locations.longitude }
    );
    withinRadius = distanceFromLocation <= (policy.radius_meters ?? 100);

    if (!withinRadius) {
      punchStatus = "VALID_WITH_EXCEPTION";
      // NEVER block. Always create pendency.
      await supabase.rpc("presence_upsert_pendency", {
        p_tenant_id: tenantId,
        p_case_id: caseId,
        p_type: "outside_radius",
        p_question: `Batida fora do raio (${Math.round(distanceFromLocation)}m de ${locationName}). Envie justificativa.`,
        p_required: true,
        p_assigned_to_role: "admin",
      });

      await supabase
        .from("cases")
        .update({ state: "PENDENTE_JUSTIFICATIVA" })
        .eq("tenant_id", tenantId)
        .eq("id", caseId);
    }
  }

  // Lateness (only on ENTRY)
  if (nextType === "ENTRY") {
    const tol = policy?.lateness_tolerance_minutes ?? 10;
    const nowHm = getLocalHm(tenantCfg.presence.time_zone);
    const startHm = parseHHMM(scheduledStartHhmm);

    if (minutesOfDay(nowHm.hh, nowHm.mm) > minutesOfDay(startHm.hh, startHm.mm) + tol) {
      punchStatus = withinRadius ? "VALID_WITH_EXCEPTION" : punchStatus;

      await supabase.rpc("presence_upsert_pendency", {
        p_tenant_id: tenantId,
        p_case_id: caseId,
        p_type: "late_arrival",
        p_question: `Entrada após tolerância (+${tol} min). Envie justificativa.`,
        p_required: true,
        p_assigned_to_role: "admin",
      });

      await supabase
        .from("cases")
        .update({ state: "PENDENTE_JUSTIFICATIVA" })
        .eq("tenant_id", tenantId)
        .eq("id", caseId);

      await supabase.from("timeline_events").insert({
        tenant_id: tenantId,
        case_id: caseId,
        event_type: "late_arrival",
        actor_type: "system",
        actor_id: null,
        message: "Atraso detectado (entrada fora da tolerância).",
        meta_json: {
          tolerance_minutes: tol,
          scheduled_start_hhmm: scheduledStartHhmm,
          scheduled_start_source: employeeCfg?.scheduled_start_hhmm ? "employee" : "tenant",
        },
        occurred_at: new Date().toISOString(),
      });
    }
  }

  // Insert punch
  const { data: inserted, error: insErr } = await supabase
    .from("time_punches")
    .insert({
      tenant_id: tenantId,
      employee_id: employeeId,
      case_id: caseId,
      type: nextType,
      latitude,
      longitude,
      accuracy_meters: accuracyMeters,
      distance_from_location: distanceFromLocation,
      within_radius: withinRadius,
      status: punchStatus,
      source,
      meta_json: {
        day,
        policy: policy
          ? {
            radius_meters: policy.radius_meters,
            lateness_tolerance_minutes: policy.lateness_tolerance_minutes,
            break_required: policy.break_required,
            allow_outside_radius: policy.allow_outside_radius,
            location_name: locationName,
          }
          : null,
        employee_config: employeeCfg
          ? {
            scheduled_start_hhmm: scheduledStartHhmm,
            scheduled_start_source: employeeCfg?.scheduled_start_hhmm ? "employee" : "tenant",
            planned_minutes: employeeCfg?.planned_minutes ?? null,
          }
          : null,
      },
    })
    .select("id,timestamp,type")
    .single();

  if (insErr) throw insErr;

  // Update state machine (happy path)
  let nextState: string | null = null;
  if (nextType === "ENTRY") nextState = "EM_EXPEDIENTE";
  if (nextType === "BREAK_START") nextState = "EM_INTERVALO";
  if (nextType === "BREAK_END") nextState = "AGUARDANDO_SAIDA";
  if (nextType === "EXIT") {
    // If break required but missing, it must be pending justification.
    if (breakRequired) {
      const { data: br, error: brErr } = await supabase
        .from("time_punches")
        .select("type")
        .eq("tenant_id", tenantId)
        .eq("case_id", caseId)
        .in("type", ["BREAK_START", "BREAK_END"])
        .limit(10);
      if (brErr) throw brErr;
      const hasStart = (br ?? []).some((r: any) => r.type === "BREAK_START");
      const hasEnd = (br ?? []).some((r: any) => r.type === "BREAK_END");

      if (!hasStart || !hasEnd) {
        await supabase.rpc("presence_upsert_pendency", {
          p_tenant_id: tenantId,
          p_case_id: caseId,
          p_type: "missing_break",
          p_question: "Intervalo obrigatório não registrado (INÍCIO e FIM). Envie justificativa.",
          p_required: true,
          p_assigned_to_role: "admin",
        });
        nextState = "PENDENTE_JUSTIFICATIVA";
      }
    }

    if (!nextState) {
      nextState = punchStatus === "VALID" ? "PENDENTE_APROVACAO" : "PENDENTE_JUSTIFICATIVA";
    }

    if (nextState === "PENDENTE_APROVACAO") {
      await supabase.rpc("presence_upsert_pendency", {
        p_tenant_id: tenantId,
        p_case_id: caseId,
        p_type: "approval_required",
        p_question: "Aprovação do gestor necessária para fechamento do dia.",
        p_required: true,
        p_assigned_to_role: "admin",
      });
    }
  }

  if (nextState) {
    await supabase
      .from("cases")
      .update({ state: nextState })
      .eq("tenant_id", tenantId)
      .eq("id", caseId);
  }

  // Audit trail
  await supabase.from("timeline_events").insert({
    tenant_id: tenantId,
    case_id: caseId,
    event_type: "presence_punch",
    actor_type: actorType,
    actor_id: actorId,
    message: `Batida registrada: ${nextType}`,
    meta_json: {
      type: nextType,
      source,
      within_radius: withinRadius,
      distance_from_location: distanceFromLocation,
      status: punchStatus,
    },
    occurred_at: new Date().toISOString(),
  });

  if (punchStatus === "VALID_WITH_EXCEPTION") {
    await supabase.from("decision_logs").insert({
      tenant_id: tenantId,
      case_id: caseId,
      agent_id: null,
      input_summary: "Registro de batida",
      output_summary: "Batida válida com exceção",
      reasoning_public: "A batida nunca é bloqueada. Quando há exceção (geofence/atraso), abrimos pendência obrigatória.",
      why_json: {
        within_radius: withinRadius,
        distance_from_location: distanceFromLocation,
        type: nextType,
      },
      confidence_json: { overall: 0.9 },
      occurred_at: new Date().toISOString(),
    });
  }

  return {
    ok: true as const,
    caseId,
    day,
    nextType,
    nextState,
    punch: {
      id: (inserted as any)?.id,
      timestamp: (inserted as any)?.timestamp,
      type: (inserted as any)?.type,
      within_radius: withinRadius,
      distance_from_location: distanceFromLocation,
      status: punchStatus,
    },
  };
}

import { createClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";

export function createSupabaseAdmin(token?: string) {
  const url = Deno.env.get("SUPABASE_URL") ?? "";
  const key = token ?? Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? "";

  if (!url || !key) {
    throw new Error("Missing SUPABASE_URL or token");
  }

  return createClient(url, key, {
    auth: { persistSession: false },
  });
}
